import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { FiShield, FiGift, FiMapPin, FiChevronDown } from 'react-icons/fi';
import { MdSearch } from 'react-icons/md';
import { useQuery } from 'react-query';
import { apiService } from '../services/api';
import { API_ENDPOINTS } from '../config/api';
import { Service, Offer } from '../types';
import { toast } from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';

interface Location {
  id: number;
  location_name: string;
}

const UserDashboard: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'services' | 'offers'>('services');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedLocation, setSelectedLocation] = useState<string>('All Locations');
  const [showLocationDropdown, setShowLocationDropdown] = useState(false);
  const [locations, setLocations] = useState<Location[]>([]);

  // Fetch locations
  const { data: locationsData } = useQuery(
    ['locations'],
    () => apiService.post(API_ENDPOINTS.LOCATIONS_MANAGER, { action: 'fetch_locations' }),
    {
      onSuccess: (data: any) => {
        if (data?.status === 'success') {
          setLocations(data.locations || []);
        }
      },
      onError: (error) => {
        console.error('Failed to fetch locations:', error);
      }
    }
  );

  // Fetch services with location filter
  const { data: servicesData, isLoading: servicesLoading, refetch: refetchServices } = useQuery(
    ['services', selectedLocation],
    () => {
      const requestData = { action: 'fetch_services' };
      if (selectedLocation !== 'All Locations') {
        requestData.location = selectedLocation;
      }
      return apiService.post(API_ENDPOINTS.FETCH_SERVICES, requestData);
    },
    {
      onError: (error) => {
        console.error('Failed to fetch services:', error);
        toast.error('Failed to load services');
      }
    }
  );

  // Fetch offers
  const { data: offersData, isLoading: offersLoading, refetch: refetchOffers } = useQuery(
    ['offers'],
    () => apiService.get(API_ENDPOINTS.FETCH_OFFERS),
    {
      onError: (error) => {
        console.error('Failed to fetch offers:', error);
        toast.error('Failed to load offers');
      }
    }
  );

  const services = servicesData?.services || [];
  const offers = offersData?.offers || [];

  // Filter services and offers based on search query
  const filteredServices = services.filter((service: Service) =>
    service.service_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    service.description.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const filteredOffers = offers.filter((offer: Offer) =>
    offer.offer_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    offer.coupon_number.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleLocationSelect = (location: string) => {
    setSelectedLocation(location);
    setShowLocationDropdown(false);
    refetchServices();
  };

  const handleServiceClick = (serviceName: string) => {
    navigate(`/service/${encodeURIComponent(serviceName)}`);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-teal-600 text-white p-4">
        <div className="max-w-7xl mx-auto">
          <h1 className="text-2xl font-bold">Welcome back, {user?.name || 'User'}!</h1>
          <p className="text-teal-100">Find the perfect service for your needs</p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto p-4">
        {/* Search Bar */}
        <div className="mb-6">
          <div className="relative">
            <MdSearch className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 text-xl" />
            <input
              type="text"
              placeholder="Search services or offers..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500"
            />
          </div>
        </div>

        {/* Location Selector */}
        <div className="mb-6">
          <div className="relative">
            <div
              onClick={() => setShowLocationDropdown(!showLocationDropdown)}
              className="flex items-center justify-between p-3 bg-white border border-gray-300 rounded-lg cursor-pointer hover:border-teal-500 transition-colors"
            >
              <div className="flex items-center space-x-3">
                <FiMapPin className="text-gray-500" />
                <div>
                  <p className="text-xs text-gray-500">Service Location</p>
                  <p className="font-medium text-gray-900">{selectedLocation}</p>
                </div>
              </div>
              <FiChevronDown className={`text-gray-500 transition-transform ${showLocationDropdown ? 'rotate-180' : ''}`} />
            </div>

            {/* Location Dropdown */}
            {showLocationDropdown && (
              <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-300 rounded-lg shadow-lg z-10 max-h-60 overflow-y-auto">
                <div
                  onClick={() => handleLocationSelect('All Locations')}
                  className="px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100"
                >
                  <p className="font-medium text-gray-900">All Locations</p>
                </div>
                {locations.map((location) => (
                  <div
                    key={location.id}
                    onClick={() => handleLocationSelect(location.location_name)}
                    className="px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 last:border-b-0"
                  >
                    <p className="font-medium text-gray-900">{location.location_name}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Tabs */}
        <div className="mb-6">
          <div className="flex space-x-1 bg-gray-200 p-1 rounded-lg">
            <button
              onClick={() => setActiveTab('services')}
              className={`flex-1 flex items-center justify-center space-x-2 py-2 px-4 rounded-md font-medium transition-colors ${
                activeTab === 'services'
                  ? 'bg-white text-teal-600 shadow-sm'
                  : 'text-gray-600 hover:text-gray-900'
              }`}
            >
              <FiShield className="w-4 h-4" />
              <span>Services ({filteredServices.length})</span>
            </button>
            <button
              onClick={() => setActiveTab('offers')}
              className={`flex-1 flex items-center justify-center space-x-2 py-2 px-4 rounded-md font-medium transition-colors ${
                activeTab === 'offers'
                  ? 'bg-white text-teal-600 shadow-sm'
                  : 'text-gray-600 hover:text-gray-900'
              }`}
            >
              <FiGift className="w-4 h-4" />
              <span>Offers ({filteredOffers.length})</span>
            </button>
          </div>
        </div>

        {/* Content */}
        {activeTab === 'services' ? (
          <div>
            {servicesLoading ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {[1, 2, 3, 4, 5, 6].map((i) => (
                  <div key={i} className="bg-white rounded-lg shadow-sm p-6 animate-pulse">
                    <div className="bg-gray-200 h-48 rounded-lg mb-4"></div>
                    <div className="bg-gray-200 h-4 rounded mb-2"></div>
                    <div className="bg-gray-200 h-3 rounded mb-4"></div>
                    <div className="bg-gray-200 h-10 rounded"></div>
                  </div>
                ))}
              </div>
            ) : filteredServices.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredServices.map((service: Service) => (
                  <div key={service.service_id} className="bg-white rounded-lg shadow-sm overflow-hidden hover:shadow-md transition-shadow">
                    <div className="h-48 bg-gray-200 flex items-center justify-center">
                      {service.image_path ? (
                        <img
                          src={`${process.env.REACT_APP_API_URL || 'http://localhost/npc_project/backend'}/${service.image_path}`}
                          alt={service.service_name}
                          className="w-full h-full object-cover"
                          onError={(e) => {
                            const target = e.target as HTMLImageElement;
                            target.style.display = 'none';
                            target.nextElementSibling?.classList.remove('hidden');
                          }}
                        />
                      ) : null}
                      <FiShield className="w-16 h-16 text-gray-400" />
                    </div>
                    <div className="p-6">
                      <h3 className="text-lg font-semibold text-gray-900 mb-2">{service.service_name}</h3>
                      <p className="text-gray-600 text-sm mb-4">{service.description}</p>
                      <button
                        onClick={() => handleServiceClick(service.service_name)}
                        className="w-full bg-teal-600 text-white py-2 px-4 rounded-lg font-medium hover:bg-teal-700 transition-colors"
                      >
                        Book Now →
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-12">
                <FiShield className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-2">No services found</h3>
                <p className="text-gray-500">
                  {searchQuery ? 'Try adjusting your search terms' : 'No services available at the moment'}
                </p>
              </div>
            )}
          </div>
        ) : (
          <div>
            {offersLoading ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {[1, 2, 3, 4, 5].map((i) => (
                  <div key={i} className="bg-white rounded-lg shadow-sm p-6 animate-pulse">
                    <div className="bg-gray-200 h-48 rounded-lg mb-4"></div>
                    <div className="bg-gray-200 h-4 rounded mb-2"></div>
                    <div className="bg-gray-200 h-3 rounded mb-4"></div>
                    <div className="bg-gray-200 h-10 rounded"></div>
                  </div>
                ))}
              </div>
            ) : filteredOffers.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredOffers.map((offer: Offer) => (
                  <div key={offer.offer_id} className="bg-white rounded-lg shadow-sm overflow-hidden hover:shadow-md transition-shadow">
                    <div className="h-48 bg-gray-200 flex items-center justify-center">
                      {offer.offer_banner_location ? (
                        <img
                          src={`${process.env.REACT_APP_API_URL || 'http://localhost/npc_project/backend'}/${offer.offer_banner_location}`}
                          alt={offer.offer_name}
                          className="w-full h-full object-cover"
                          onError={(e) => {
                            const target = e.target as HTMLImageElement;
                            target.style.display = 'none';
                            target.nextElementSibling?.classList.remove('hidden');
                          }}
                        />
                      ) : null}
                      <FiGift className="w-16 h-16 text-gray-400" />
                    </div>
                    <div className="p-6">
                      <h3 className="text-lg font-semibold text-gray-900 mb-2">{offer.offer_name}</h3>
                      <div className="space-y-2 mb-4">
                        <p className="text-sm text-gray-600">
                          <span className="font-medium">Coupon:</span> {offer.coupon_number}
                        </p>
                        <p className="text-sm text-gray-600">
                          <span className="font-medium">Discount:</span> {offer.offer_percentage}% off
                        </p>
                        <p className="text-sm text-gray-600">
                          <span className="font-medium">Status:</span> 
                          <span className={`ml-1 px-2 py-1 rounded-full text-xs font-medium ${
                            offer.status === 'Active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                          }`}>
                            {offer.status}
                          </span>
                        </p>
                      </div>
                      <button
                        onClick={() => handleServiceClick('General Service')}
                        className="w-full bg-teal-600 text-white py-2 px-4 rounded-lg font-medium hover:bg-teal-700 transition-colors"
                      >
                        Book Now →
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-12">
                <FiGift className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-2">No offers found</h3>
                <p className="text-gray-500">
                  {searchQuery ? 'Try adjusting your search terms' : 'No offers available at the moment'}
                </p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default UserDashboard;
